Here are the public test cases for feature6_4_glob_patterns:
{
  "description": "Resolves a multi-valued glob option. A null or empty value yields the role's default glob list; a non-empty value is taken as-is (with empty entries dropped). Reports the number of patterns followed by each pattern. Defaults per role: include-sources->[src/**/*.cs], exclude-sources->[**/bin/**/*.cs, **/obj/**/*.cs], include-tests->[tests/**/*.cs, test/**/*.cs], exclude-tests->[**/bin/**/*.cs, **/obj/**/*.cs], include-assemblies->[**/*.dll], exclude-assemblies->[**/obj/**/*.dll].",
  "cases": [
    {
      "input": {
        "op": "resolve_globs",
        "role": "include-sources",
        "value": null
      },
      "expected_output": "count=1\nsrc/**/*.cs\n"
    },
    {
      "input": {
        "op": "resolve_globs",
        "role": "include-tests",
        "value": null
      },
      "expected_output": "count=2\ntests/**/*.cs\ntest/**/*.cs\n"
    },
    {
      "input": {
        "op": "resolve_globs",
        "role": "exclude-sources",
        "value": null
      },
      "expected_output": "count=2\n**/bin/**/*.cs\n**/obj/**/*.cs\n"
    },
    {
      "input": {
        "op": "resolve_globs",
        "role": "include-assemblies",
        "value": null
      },
      "expected_output": "count=1\n**/*.dll\n"
    },
    {
      "input": {
        "op": "resolve_globs",
        "role": "exclude-assemblies",
        "value": null
      },
      "expected_output": "count=1\n**/obj/**/*.dll\n"
    },
    {
      "input": {
        "op": "resolve_globs",
        "role": "include-tests",
        "value": []
      },
      "expected_output": "count=2\ntests/**/*.cs\ntest/**/*.cs\n"
    },
    {
      "input": {
        "op": "resolve_globs",
        "role": "include-sources",
        "value": [
          "a.cs",
          "**/a.cs"
        ]
      },
      "expected_output": "count=2\na.cs\n**/a.cs\n"
    }
  ]
}

